function instructionRuleKindFromPath(path: string): InstructionStackSourceKind {
  const normalized = path.replace(/\\/g, "/").toLowerCase();
  if (normalized.endsWith("/agents.md") || normalized === "agents.md") return "codex";
  if (normalized.endsWith("/claude.md") || normalized === "claude.md") return "claude";
  if (normalized.includes("/steering/") || normalized.includes("/specs/") || normalized.includes("/hooks/")) return "kiro";
  return "lumen";
}

function instructionRuleInclusionFromPath(path: string) {
  const normalized = path.replace(/\\/g, "/").toLowerCase();
  if (normalized.endsWith("/agents.md") || normalized === "agents.md") return { inclusion: "project-scope", mode: "always", scope: "nearest-project-scope" };
  if (normalized.endsWith("/claude.md") || normalized === "claude.md") return { inclusion: "project-memory", mode: "always", scope: "nearest-project-memory" };
  if (normalized.includes("/steering/")) {
    const manual = /manual|optional|archive|draft/.test(normalized);
    const fileMatch = /filematch|file-match|glob|pattern/.test(normalized);
    return { inclusion: "steering", mode: fileMatch ? "fileMatch" : manual ? "manual" : "always", scope: "workspace-steering" };
  }
  if (normalized.includes("/specs/")) return { inclusion: "spec", mode: "manual", scope: "current-spec" };
  if (normalized.includes("/hooks/")) return { inclusion: "hook", mode: "event-bound", scope: "workspace-hooks" };
  return { inclusion: "instruction", mode: "manual", scope: "workspace-rule" };
}

function instructionRuleLabelFromPath(path: string) {
  const normalized = path.replace(/\\/g, "/");
  const name = normalized.split("/").filter(Boolean).pop() || normalized || "rule";
  const lower = name.toLowerCase();
  if (lower === "agents.md") return "Codex AGENTS.md";
  if (lower === "claude.md") return "Claude CLAUDE.md";
  if (normalized.toLowerCase().includes("/steering/")) return `Steering · ${name}`;
  if (normalized.toLowerCase().includes("/specs/")) return `Spec · ${name}`;
  if (normalized.toLowerCase().includes("/hooks/")) return `Hook · ${name}`;
  return `Rule · ${name}`;
}

function isInstructionRulePath(path: string) {
  const normalized = path.replace(/\\/g, "/").toLowerCase();
  if (normalized === "agents.md" || normalized.endsWith("/agents.md")) return true;
  if (normalized === "claude.md" || normalized.endsWith("/claude.md")) return true;
  if (!normalized.endsWith(".md")) return false;
  return normalized.includes(".lumen/steering/")
    || normalized.includes(".lumen/specs/")
    || normalized.includes(".lumen/hooks/");
}

function discoverInstructionRuleFiles(
  scanItems: WorkspaceScanIndexItem[],
  workspace: WorkspaceManagerRow | null,
  rootPath: string,
): InstructionRuleFile[] {
  const workspaceId = workspace?.book.id || "";
  const workspaceTitle = workspace?.title || "";
  return scanItems
    .filter((item) => !item.isDir && isInstructionRulePath(item.path))
    .sort((a, b) => {
      const priorityA = instructionRulePriority(a.path);
      const priorityB = instructionRulePriority(b.path);
      if (priorityA !== priorityB) return priorityA - priorityB;
      if (a.depth !== b.depth) return a.depth - b.depth;
      return a.path.localeCompare(b.path);
    })
    .slice(0, 24)
    .map((item, index) => {
      const inclusion = instructionRuleInclusionFromPath(item.path);
      return {
        id: `discovered-${workspaceId || "workspace"}-${item.path.replace(/[^a-z0-9]+/gi, "-").replace(/^-|-$/g, "").toLowerCase() || index}`,
        kind: instructionRuleKindFromPath(item.path),
        label: instructionRuleLabelFromPath(item.path),
        path: item.path,
        workspaceId,
        workspaceTitle,
        rootPath,
        readPath: rootPath ? workspaceIndexedReadPath({
          workspaceId: workspaceId || "workspace",
          workspaceTitle: workspaceTitle || "workspace",
          rootPath,
          accessProfile: "full_access",
          at: Date.now(),
          status: "discovered",
          maxDepth: 0,
          limit: 0,
          returned: 0,
          hasMore: false,
          skipped: 0,
          fileCount: 0,
          dirCount: 0,
          items: [],
          policy: {},
          request: null,
        }, item) : item.path,
        scope: inclusion.scope,
        inclusion: inclusion.inclusion,
        inclusionMode: inclusion.mode,
        priority: instructionRulePriority(item.path) + Math.min(item.depth, 9),
        status: "discovered",
        content: "",
        summary: "workspace_scan 已发现，等待只读读取摘要。",
        discovered: true,
        size: item.size,
        depth: item.depth,
        modifiedAt: item.modifiedAt,
        result: null,
      };
    });
}

function instructionRulePriority(path: string) {
  const normalized = path.replace(/\\/g, "/").toLowerCase();
  if (normalized === "agents.md") return 30;
  if (normalized.endsWith("/agents.md")) return 31;
  if (normalized === "claude.md") return 40;
  if (normalized.endsWith("/claude.md")) return 41;
  if (normalized.includes("/steering/")) return 50;
  if (normalized.includes("/specs/")) return 60;
  if (normalized.includes("/hooks/")) return 70;
  return 90;
}

function summarizeInstructionRule(content: string) {
  const plain = content
    .replace(/```[\s\S]*?```/g, " ")
    .split(/\r?\n/)
    .map((line) => line.replace(/^#+\s*/, "").replace(/^[-*]\s+\[[ xX]\]\s*/, "").replace(/^[-*]\s+/, "").trim())
    .filter(Boolean);
  const headings = plain.filter((line) => line.length <= 80).slice(0, 6);
  const sample = plain.join(" ").replace(/\s+/g, " ").slice(0, 420);
  return (headings.length ? headings.join("；") : sample) || "文件为空或暂无可摘要内容。";
}

function instructionRuleDraftKindForPath(path: string): InstructionRuleDraftFile["kind"] {
  const inferred = instructionRuleKindFromPath(path);
  return inferred === "thread" || inferred === "workspace" || inferred === "safety" ? "lumen" : inferred;
}

function instructionRulePathDepth(path: string) {
  return path.replace(/\\/g, "/").split("/").filter(Boolean).length;
}

function buildInstructionRuleScopeAuditRows(
  files: InstructionRuleFile[],
  draft: InstructionRuleDraftSnapshot,
  layers: InstructionStackLayer[],
): InstructionRuleScopeAuditRow[] {
  const synced = files.filter((file) => file.status === "ok");
  const missing = files.filter((file) => file.status !== "ok");
  const agents = synced.filter((file) => file.kind === "codex");
  const nestedAgents = agents.filter((file) => instructionRulePathDepth(file.path) > 1);
  const claude = synced.filter((file) => file.kind === "claude");
  const steering = synced.filter((file) => file.inclusion === "steering");
  const specs = synced.filter((file) => file.inclusion === "spec");
  const hooks = synced.filter((file) => file.inclusion === "hook");
  const drafts = draft.files;
  const hasDrafts = drafts.length > 0;
  const pathCounts = files.reduce<Record<string, number>>((acc, file) => {
    const key = file.path.replace(/\\/g, "/").toLowerCase();
    acc[key] = (acc[key] || 0) + 1;
    return acc;
  }, {});
  const duplicatePaths = Object.entries(pathCounts).filter(([, count]) => count > 1).map(([path]) => path);
  const rows: InstructionRuleScopeAuditRow[] = [
    {
      id: "source-boundary",
      label: "来源边界",
      status: "locked",
      severity: "pass",
      detail: "参考资料、官方文档、开源项目和本地研究资料用于架构拆解、功能对标和风险识别；落地代码按本项目架构实现。",
      evidence: layers.filter((layer) => layer.kind === "safety" || layer.id === "public-source-boundary").slice(0, 3).map((layer) => layer.label),
      nextAction: "继续把参考资料转成产品机制、本地协议和可验证的 UI / 运行时能力。",
    },
    {
      id: "codex-scope",
      label: "AGENTS.md 作用域",
      status: agents.length ? "active" : hasDrafts ? "draft" : "missing",
      severity: agents.length ? (nestedAgents.length ? "info" : "pass") : "warn",
      detail: agents.length
        ? nestedAgents.length
          ? `已同步 ${agents.length} 个 AGENTS.md，其中 ${nestedAgents.length} 个为嵌套作用域；越接近目标文件优先级越高。`
          : "已同步项目根 AGENTS.md，当前可作为 Codex 式项目级指令。"
        : hasDrafts
          ? "已生成 AGENTS.md 草案，但尚未通过 write_file 审批落地。"
          : "尚未读取到 AGENTS.md；Agent 只能依赖内置目标模式和线程上下文。",
      evidence: (agents.length ? agents : drafts.filter((file) => file.path.toLowerCase().endsWith("agents.md"))).slice(0, 4).map((file) => file.path),
      nextAction: agents.length ? "后续补任务文件匹配，显示 nested AGENTS 与当前目标路径的最近匹配。" : "生成规则草案并提交 write_file 审批。",
    },
    {
      id: "claude-memory",
      label: "CLAUDE.md 项目记忆",
      status: claude.length ? "active" : hasDrafts ? "draft" : "missing",
      severity: claude.length ? "pass" : "warn",
      detail: claude.length
        ? `已同步 ${claude.length} 个 CLAUDE.md，可作为项目记忆与协作约定。`
        : hasDrafts
          ? "CLAUDE.md 草案已生成，等待审批后成为项目记忆层。"
          : "尚未读取到 CLAUDE.md；项目偏好仍主要来自路线图和线程记录。",
      evidence: (claude.length ? claude : drafts.filter((file) => file.path.toLowerCase().endsWith("claude.md"))).slice(0, 4).map((file) => file.path),
      nextAction: claude.length ? "保持 CLAUDE.md 与长期记忆分层，不把它混进 L1/L2 原始记忆。" : "生成规则草案或添加项目 CLAUDE.md。",
    },
    {
      id: "kiro-steering",
      label: "Steering / Specs",
      status: steering.length || specs.length ? "active" : hasDrafts ? "draft" : "missing",
      severity: steering.length || specs.length ? "pass" : "warn",
      detail: steering.length || specs.length
        ? `已同步 Steering ${steering.length} / Specs ${specs.length}；always/manual/fileMatch 需要在任务上下文中明确展示。`
        : hasDrafts
          ? "Steering / Specs 草案已生成，尚未通过审批落地。"
          : "尚未读取到 `.lumen` Steering / Specs；规格化任务仍以本地草案为主。",
      evidence: [...steering, ...specs].length ? [...steering, ...specs].slice(0, 5).map((file) => `${file.path} · ${file.inclusionMode}`) : drafts.filter((file) => file.path.includes(".lumen/")).slice(0, 5).map((file) => `${file.path} · ${file.inclusionMode}`),
      nextAction: "补规则文件树和逐文件 Diff，让 Steering / Specs 可以单独接受、拒绝或更新。",
    },
    {
      id: "hooks-boundary",
      label: "Hooks 边界",
      status: hooks.length ? "active" : hasDrafts ? "draft" : "gated",
      severity: "pass",
      detail: hooks.length
        ? "Hooks 文件已同步，但仍只是事件绑定规则；启用 Hook 必须另走审批。"
        : "Hooks 仍处于草案或缺失状态；不会注册系统 Hook。",
      evidence: (hooks.length ? hooks : drafts.filter((file) => file.path.includes("/hooks/"))).map((file) => `${file.path} · event-bound`).slice(0, 4),
      nextAction: "后续把 UserPromptSubmit / PreToolUse / PostToolUse 做成可审批的 Hook Registry。",
    },
    {
      id: "missing-rules",
      label: "缺失与初始化",
      status: missing.length ? "needs-draft" : "complete",
      severity: missing.length ? "warn" : "pass",
      detail: missing.length
        ? `${missing.length} 个规则文件尚未读取成功；可用规则初始化草案补齐，但必须走 write_file 审批。`
        : "当前规则文件均已同步成功。",
      evidence: missing.slice(0, 7).map((file) => `${file.path} · ${statusLabel(file.status)}`),
      nextAction: missing.length ? "点击生成规则草案，再提交规则审批。" : "继续做作用域冲突审计和任务路径匹配。",
    },
    {
      id: "duplicate-paths",
      label: "路径冲突",
      status: duplicatePaths.length ? "conflict" : "clear",
      severity: duplicatePaths.length ? "block" : "pass",
      detail: duplicatePaths.length
        ? `发现 ${duplicatePaths.length} 个重复规则路径，可能导致摘要或注入重复。`
        : "当前规则路径没有重复记录。",
      evidence: duplicatePaths.slice(0, 5),
      nextAction: duplicatePaths.length ? "保留更接近当前工作区的规则，隐藏重复 fallback。" : "后续补真正的 nested scope 优先级解释。",
    },
  ];
  return rows;
}

function normalizeRulePath(path: string) {
  return path.replace(/\\/g, "/").replace(/^\.\//, "").replace(/\/+/g, "/").toLowerCase();
}

function parentDir(path: string) {
  const parts = normalizeRulePath(path).split("/").filter(Boolean);
  if (!parts.length) return "";
  parts.pop();
  return parts.join("/");
}

function instructionRuleAppliesToTarget(file: Pick<InstructionRuleFile, "path" | "kind" | "inclusion" | "inclusionMode">, targetPath: string) {
  const rulePath = normalizeRulePath(file.path);
  const target = normalizeRulePath(targetPath);
  const dir = parentDir(rulePath);
  if (!target) {
    if (file.kind === "claude") return { applies: true, reason: "无明确文件路径时，CLAUDE.md 仍作为项目记忆随线程进入上下文。" };
    if (file.inclusion === "spec") return { applies: true, reason: "无明确文件路径时，Specs 仍作为当前任务的需求/设计/任务上下文参与计划审查。" };
    if (file.inclusion === "hook") return { applies: false, reason: "无明确文件路径；Hooks 是 event-bound，只在对应事件和审批后触发。" };
    if (file.inclusionMode === "always") return { applies: true, reason: "无明确文件路径；always 规则默认进入线程上下文。" };
    return { applies: false, reason: `无明确文件路径；${file.inclusionMode} 规则需要任务显式选择或路径匹配。` };
  }
  if (file.kind === "codex") {
    const applies = !dir || target === rulePath || target.startsWith(`${dir}/`);
    return {
      applies,
      reason: applies
        ? dir ? `AGENTS.md 位于 ${dir}，覆盖该目录及子路径。` : "项目根 AGENTS.md 覆盖整个工作区。"
        : `目标路径不在 ${dir || "项目根"} 作用域内。`,
    };
  }
  if (file.kind === "claude") {
    return { applies: true, reason: "CLAUDE.md 作为项目记忆和协作约定，默认随线程进入上下文。" };
  }
  if (file.inclusion === "steering") {
    if (file.inclusionMode === "fileMatch") {
      const applies = target.includes(parentDir(rulePath).replace(".lumen/steering", "").replace(/^\/+/, ""));
      return { applies, reason: applies ? "fileMatch Steering 与目标路径模式匹配。" : "fileMatch Steering 暂未匹配当前目标路径。" };
    }
    return { applies: file.inclusionMode === "always", reason: file.inclusionMode === "always" ? "always Steering 默认进入上下文。" : "manual Steering 需要任务显式选择。" };
  }
  if (file.inclusion === "spec") {
    return { applies: true, reason: "当前 Specs 作为任务需求/设计/任务上下文，可参与计划审查。" };
  }
  if (file.inclusion === "hook") {
    return { applies: false, reason: "Hooks 是 event-bound；只有对应事件触发且审批后才执行。" };
  }
  return { applies: file.inclusionMode === "always", reason: `${file.inclusionMode} 规则按声明模式处理。` };
}

function buildInstructionRuleMatchRows(
  files: InstructionRuleFile[],
  draftFiles: InstructionRuleDraftFile[],
  target: InstructionRuleMatchTarget,
): InstructionRuleMatchRow[] {
  const synced = files.filter((file) => file.status === "ok");
  const sourceFiles: Array<InstructionRuleFile | InstructionRuleDraftFile> = synced.length ? synced : draftFiles;
  const rows = sourceFiles.map((file, index): InstructionRuleMatchRow => {
    const synthetic = !("status" in file);
    const match = instructionRuleAppliesToTarget(file, target.path);
    return {
      id: `match-${file.path}-${index}`,
      label: "label" in file ? file.label : file.title,
      path: file.path,
      kind: file.kind,
      status: synthetic ? "draft" : file.status,
      reason: synthetic ? `草案规则：${match.reason}` : match.reason,
      scope: file.scope,
      inclusion: file.inclusion,
      inclusionMode: file.inclusionMode,
      priority: file.priority,
      applies: match.applies,
    };
  });
  const activeAgents = rows.filter((row) => row.kind === "codex" && row.applies).sort((a, b) => {
    const depthDelta = instructionRulePathDepth(b.path) - instructionRulePathDepth(a.path);
    if (depthDelta !== 0) return depthDelta;
    return a.priority - b.priority;
  });
  const nearestAgent = activeAgents[0]?.path;
  return rows
    .map((row) => {
      if (row.kind === "codex" && row.applies && nearestAgent && row.path !== nearestAgent) {
        return {
          ...row,
          status: "shadowed",
          reason: `${row.reason} 但当前更近的 AGENTS.md 是 ${nearestAgent}。`,
          applies: false,
        };
      }
      return row;
    })
    .sort((a, b) => {
      if (a.applies !== b.applies) return a.applies ? -1 : 1;
      if (a.kind === "codex" && b.kind === "codex") {
        const depthDelta = instructionRulePathDepth(b.path) - instructionRulePathDepth(a.path);
        if (depthDelta !== 0) return depthDelta;
      }
      return a.priority - b.priority;
    });
}

function threadMessageRoleFromEvent(kind: AgentThreadEventKind): AgentThreadMessageRole {
  if (kind === "draft") return "assistant";
  if (kind === "worker" || kind === "approval" || kind === "diff" || kind === "write") return "tool";
  return "system";
}

function normalizeAgentThreadMessage(value: unknown): AgentThreadMessage | null {
  const record = asRecord(value);
  const id = asString(record.id);
  const role = asString(record.role, "system") as AgentThreadMessageRole;
  if (!id) return null;
  const attachments = asRecordList(record.attachments)
    .map(normalizeAgentThreadMessageAttachment)
    .filter((item): item is AgentThreadMessageAttachment => Boolean(item))
    .slice(0, 8);
  return {
    id,
    role: ["user", "assistant", "system", "tool"].includes(role) ? role : "system",
    title: publicFacingText(asString(record.title, "线程消息")),
    content: publicFacingText(asString(record.content, asString(record.detail, ""))),
    status: asString(record.status, "recorded"),
    at: asNumber(record.at, Date.now()),
    sourceRef: asString(record.sourceRef),
    attachments,
  };
}

function createAgentThreadRecord(input: {
  title?: string;
  task?: string;
  status?: string;
  summary?: string;
  workspaceId?: string | null;
  workspaceTitle?: string;
  workspaceDomain?: string;
} = {}): AgentThreadRecord {
  const now = Date.now();
  const task = input.task !== undefined ? input.task.trim() : input.title || "继续完善织梦写作台";
  const summary = input.summary || "线程已创建，等待上下文包、后台任务复核和审批记录。";
  const messages = [
    createAgentThreadMessage({
      role: "system",
      title: "线程创建",
      content: summary,
      status: input.status || "current",
      at: now,
    }),
    ...(task ? [createAgentThreadMessage({
      role: "user",
      title: "目标任务",
      content: task,
      status: "current",
      at: now + 1,
    })] : []),
  ];
  return {
    id: `thread-${uid()}`,
    title: input.title || compactThreadTitle(task, "当前目标：织梦写作台"),
    task,
    status: input.status || "current",
    summary,
    createdAt: now,
    updatedAt: now,
    workspaceId: input.workspaceId ?? null,
    workspaceTitle: input.workspaceTitle,
    workspaceDomain: input.workspaceDomain,
    approvalCount: 0,
    approvalIds: [],
    approvalSnapshots: [],
    diffCount: 0,
    events: [{
      id: `event-${uid()}`,
      kind: "system",
      title: "线程创建",
      detail: summary || "已进入对话线程，可恢复任务、绑定工作区并沉淀审批轨迹。",
      status: input.status || "current",
      at: now,
    }],
    messages,
    contextAttachments: [
      ...(input.workspaceId ? [createAgentThreadContextAttachment({
        kind: "workspace",
        title: input.workspaceTitle || "当前工作区",
        detail: input.workspaceDomain || "已绑定工作区上下文。",
        ref: input.workspaceId,
        source: "workspace",
        status: "bound",
        at: now,
      })] : []),
    ],
  };
}

function normalizeAgentThreadRecord(value: unknown): AgentThreadRecord | null {
  const record = asRecord(value);
  const id = asString(record.id);
  if (!id) return null;
  const now = Date.now();
  const events = asRecordList(record.events).map((event) => ({
    id: asString(event.id, `event-${uid()}`),
    kind: asString(event.kind, "note") as AgentThreadEventKind,
    title: publicFacingText(asString(event.title, "线程事件")),
    detail: publicFacingText(asString(event.detail, asString(event.summary, ""))),
    status: asString(event.status, "recorded"),
    at: asNumber(event.at, now),
  })).slice(0, 24);
  const messages = asRecordList(record.messages)
    .map(normalizeAgentThreadMessage)
    .filter((message): message is AgentThreadMessage => Boolean(message))
    .sort((a, b) => a.at - b.at)
    .slice(-36);
  const fallbackMessages = [
    createAgentThreadMessage({
      role: "system",
      title: "线程恢复",
      content: asString(record.summary, "从本地记录恢复对话线程。"),
      status: "restored",
      at: now,
    }),
    ...(asString(record.task) ? [createAgentThreadMessage({
      role: "user" as const,
      title: "目标任务",
      content: asString(record.task),
      status: asString(record.status, "current"),
      at: now + 1,
    })] : []),
    ...events.slice().reverse().slice(-10).map((event) => createAgentThreadMessage({
      role: threadMessageRoleFromEvent(event.kind),
      title: event.title,
      content: event.detail,
      status: event.status,
      at: event.at,
    })),
  ].sort((a, b) => a.at - b.at).slice(-36);
  const contextAttachments = asRecordList(record.contextAttachments)
    .map(normalizeAgentThreadContextAttachment)
    .filter((item): item is AgentThreadContextAttachment => Boolean(item))
    .sort((a, b) => b.at - a.at)
    .slice(0, 24);
  const approvalIds = Array.from(new Set([
    ...asArray(record.approvalIds).map((item) => String(item)).filter(Boolean),
    ...events.flatMap((event) => {
      const match = event.detail.match(/approval\s+([A-Za-z0-9_.:-]+)/i);
      return match?.[1] ? [match[1]] : [];
    }),
  ]));
  const approvalSnapshots = asRecordList(record.approvalSnapshots)
    .map((item) => approvalSnapshotFromRecord(item))
    .filter((item): item is AgentThreadApprovalSnapshot => Boolean(item));
  return {
    id,
    title: publicFacingText(asString(record.title, "未命名对话线程")),
    task: publicFacingText(asString(record.task, asString(record.title, ""))),
    status: asString(record.status, "current"),
    summary: publicFacingText(asString(record.summary, "")),
    createdAt: asNumber(record.createdAt, now),
    updatedAt: asNumber(record.updatedAt, now),
    pinnedAt: asNumber(record.pinnedAt, 0) || undefined,
    archivedAt: asNumber(record.archivedAt, 0) || undefined,
    workspaceId: asString(record.workspaceId) || null,
    workspaceTitle: publicFacingText(asString(record.workspaceTitle)),
    workspaceDomain: publicFacingText(asString(record.workspaceDomain)),
    workerJobId: asString(record.workerJobId),
    approvalCount: Math.max(asNumber(record.approvalCount), approvalIds.length),
    approvalIds,
    approvalSnapshots,
    diffCount: asNumber(record.diffCount),
    events: events.length ? events : [{
      id: `event-${uid()}`,
      kind: "system",
      title: "线程恢复",
      detail: "从本地记录恢复对话线程。",
      status: "restored",
      at: now,
    }],
    messages: messages.length ? messages : fallbackMessages,
    contextAttachments,
  };
}

function agentThreadSpaceKey(workspaceId?: string | null) {
  return workspaceId ? `workspace:${workspaceId}` : "unbound";
}

function agentThreadSpaceLabel(spaceKey: string, workspaces: Array<{ book: BookProject; title: string }>) {
  if (spaceKey === "unbound") return "自由对话";
  const workspaceId = spaceKey.replace(/^workspace:/, "");
  return workspaces.find((item) => item.book.id === workspaceId)?.title || workspaceId || "未知项目";
}

function buildAgentThreadSpacesIndex(threads: AgentThreadRecord[], migratedFrom?: string): AgentThreadSpacesIndex {
  const spaces: Record<string, AgentThreadRecord[]> = {};
  threads.forEach((thread) => {
    const key = agentThreadSpaceKey(thread.workspaceId);
    spaces[key] = [...(spaces[key] || []), thread];
  });
  Object.keys(spaces).forEach((key) => {
    spaces[key] = spaces[key].sort((a, b) => b.updatedAt - a.updatedAt);
  });
  return {
    version: 1,
    migratedFrom,
    updatedAt: Date.now(),
    spaces,
  };
}

function normalizeAgentThreadSpacesIndex(value: unknown): AgentThreadSpacesIndex | null {
  const record = asRecord(value);
  const spacesRecord = asRecord(record.spaces);
  const spaces: Record<string, AgentThreadRecord[]> = {};
  Object.entries(spacesRecord).forEach(([key, rawThreads]) => {
    const threads = asArray(rawThreads)
      .map(normalizeAgentThreadRecord)
      .filter((thread): thread is AgentThreadRecord => Boolean(thread));
    if (threads.length) spaces[key || "unbound"] = threads.sort((a, b) => b.updatedAt - a.updatedAt);
  });
  if (!Object.keys(spaces).length) return null;
  return {
    version: 1,
    migratedFrom: asString(record.migratedFrom),
    updatedAt: asNumber(record.updatedAt, Date.now()),
    spaces,
  };
}

function flattenAgentThreadSpaces(index: AgentThreadSpacesIndex) {
  return Object.values(index.spaces).flat().sort((a, b) => b.updatedAt - a.updatedAt);
}

function loadAgentThreads() {
  const spacesIndex = normalizeAgentThreadSpacesIndex(
    loadJSONWithLegacyKeys<unknown>(AGENT_THREAD_SPACES_KEY, null),
  );
  if (spacesIndex) {
    const threads = flattenAgentThreadSpaces(spacesIndex);
    if (threads.length) return threads;
  }
  const legacyThreads = (
    loadJSON<unknown[] | null>(AGENT_THREADS_KEY, null)
    || loadJSON<unknown[] | null>(LEGACY_AGENT_THREADS_KEY, null)
    || []
  )
    .map(normalizeAgentThreadRecord)
    .filter((thread): thread is AgentThreadRecord => Boolean(thread))
    .sort((a, b) => b.updatedAt - a.updatedAt);
  if (legacyThreads.length) {
    saveJSON(AGENT_THREAD_SPACES_KEY, buildAgentThreadSpacesIndex(legacyThreads, LEGACY_AGENT_THREADS_KEY));
    return legacyThreads;
  }
  const threads = [createAgentThreadRecord()];
  saveJSON(AGENT_THREAD_SPACES_KEY, buildAgentThreadSpacesIndex(threads, "initial"));
  return threads.length ? threads : [createAgentThreadRecord()];
}

function normalizeRuntimeLogEntry(value: unknown): RuntimeLogEntry | null {
  const record = asRecord(value);
  const id = asString(record.id);
  if (!id) return null;
  const channel = asString(record.channel, "output") as RuntimeLogChannel;
  return {
    id,
    channel,
    title: asString(record.title, "运行事件"),
    detail: asString(record.detail),
    status: asString(record.status, "recorded"),
    at: asNumber(record.at, Date.now()),
    source: asString(record.source) || undefined,
    type: asString(record.type) || undefined,
    ref: asString(record.ref) || undefined,
    record: Object.keys(asRecord(record.record)).length ? asRecord(record.record) : undefined,
  };
}

function runtimeLogEntryFromGatewayEvent(value: unknown): RuntimeLogEntry | null {
  const record = asRecord(value);
  const source = asString(record.source, "gateway");
  const type = asString(record.type, "event");
  const ref = asString(record.ref);
  const id = asString(record.id, `gateway-${source}-${type}-${ref}-${asString(record.at)}`);
  const atIso = asString(record.at);
  const at = atIso ? Date.parse(atIso) : asNumber(record.at_epoch) * 1000;
  const channel: RuntimeLogChannel = source === "workers"
    ? "workers"
    : source === "approvals"
      ? "approvals"
      : "gateway";
  if (!id) return null;
  return {
    id: `rt-${id}`,
    channel,
    title: asString(record.title, `${source} · ${type}`),
    detail: [
      asString(record.detail),
      ref ? `ref: ${ref}` : "",
      source ? `source: ${source}` : "",
    ].filter(Boolean).join(" · "),
    status: asString(record.status, "recorded"),
    at: Number.isFinite(at) && at > 0 ? at : Date.now(),
    source,
    type,
    ref,
    record: asRecord(record.record),
  };
}

function workerTimelineJobId(value: unknown) {
  const record = asRecord(value);
  return asString(
    record.job_id,
    asString(record.jobId, asString(record.id, asString(record.ref))),
  );
}

function workerTimelineTime(value: unknown) {
  const record = asRecord(value);
  const raw = record.at || record.updated_at || record.created_at || record.time || record.timestamp;
  if (typeof raw === "number" && Number.isFinite(raw)) return raw > 1_000_000_000_000 ? raw : raw * 1000;
  const parsed = Date.parse(asString(raw));
  return Number.isFinite(parsed) && parsed > 0 ? parsed : Date.now();
}

function workerTimelineItemFromJob(job: JsonRecord): WorkerTimelineItem | null {
  const jobId = workerTimelineJobId(job);
  if (!jobId) return null;
  const payload = asRecord(job.payload);
  const result = asRecord(job.result);
  const kind = asString(job.kind, asString(payload.kind, "worker_job"));
  const status = asString(job.status, "unknown");
  const command = asString(payload.command, asString(payload.action, asString(payload.model_id, asString(payload.kind))));
  return {
    id: `job-${jobId}`,
    jobId,
    source: "job",
    title: `${kind} · ${statusLabel(status)}`,
    detail: asString(job.purpose, asString(result.message, asString(result.reason, command || "Worker job"))),
    status,
    at: workerTimelineTime(job),
    kind,
    ref: asString(job.proposal_path, asString(job.merge_proposal_path, asString(job.id))),
  };
}

function workerTimelineItemFromEvent(event: JsonRecord): WorkerTimelineItem | null {
  const jobId = workerTimelineJobId(event);
  if (!jobId) return null;
  const type = asString(event.type, "worker_event");
  const status = asString(event.status, "recorded");
  return {
    id: `event-${workerEventKey(event)}`,
    jobId,
    source: "event",
    title: `${type} · ${modelWorkerEventLabel(event)}`,
    detail: asString(event.message, asString(event.text, asString(event.detail, asString(event.stage, "")))),
    status,
    at: workerTimelineTime(event),
    kind: type,
    ref: asString(event.stage, asString(event.ref)),
  };
}

function workerTimelineItemFromRuntime(entry: RuntimeLogEntry): WorkerTimelineItem | null {
  if (entry.channel !== "workers") return null;
  const refMatch = entry.detail.match(/ref:\s*([^·\s]+)/);
  const titleMatch = entry.title.match(/(?:worker|job)[^\w-]*([A-Za-z0-9_.:-]{6,})/i);
  const jobId = refMatch?.[1] || titleMatch?.[1] || entry.id.replace(/^rt-/, "");
  return {
    id: `runtime-${entry.id}`,
    jobId,
    source: "runtime",
    title: entry.title,
    detail: entry.detail,
    status: entry.status,
    at: entry.at,
    kind: "runtime_event",
    ref: jobId,
  };
}

function dedupeWorkerTimeline(items: WorkerTimelineItem[]) {
  const map = new Map<string, WorkerTimelineItem>();
  items.forEach((item) => {
    const key = [item.source, item.jobId, item.kind, item.status, Math.round(item.at / 1000), item.detail.slice(0, 80)].join("|");
    if (!map.has(key)) map.set(key, item);
  });
  return Array.from(map.values()).sort((a, b) => b.at - a.at);
}

