                      <MiniStat label="禁用" value={`${workspaceDisabledSkillRows.length}/${selectedWorkspaceSkillSet.disabledSkillKeys.length}`} tone={selectedWorkspaceSkillSet.disabledSkillKeys.length ? "text-amber-300" : "text-slate-400"} />
