                <ActionButton label="召回记忆" icon={<FileText className="h-3.5 w-3.5" />} onClick={() => void runQuickAction("记忆召回", "memory_retrieve", { task: "继续完善织梦写作台", limit: 8 })} disabled={!state.online || quickAction.status === "running"} />
